ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS bio text, ADD COLUMN IF NOT EXISTS specialty text, ADD COLUMN IF NOT EXISTS pronouns text, ADD COLUMN IF NOT EXISTS website text, ADD COLUMN IF NOT EXISTS portfolio_url text; CREATE TABLE IF NOT EXISTS public.tasks (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), owner_id uuid NOT NULL, title text NOT NULL, notes text, urgent boolean NOT NULL DEFAULT false, important boolean NOT NULL DEFAULT false, done boolean NOT NULL DEFAULT false, due_date date, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.tasks ENABLE ROW LEVEL SECURITY; CREATE POLICY "Team reads tasks" ON public.tasks FOR SELECT TO authenticated USING (public.is_team_member(auth.uid())); CREATE POLICY "Team creates own tasks" ON public.tasks FOR INSERT TO authenticated WITH CHECK (public.is_team_member(auth.uid()) AND owner_id = auth.uid()); CREATE POLICY "Owner or admin updates tasks" ON public.tasks FOR UPDATE TO authenticated USING (owner_id = auth.uid() OR public.has_role(auth.uid(), 'admin')) WITH CHECK (owner_id = auth.uid() OR public.has_role(auth.uid(), 'admin')); CREATE POLICY "Owner or admin deletes tasks" ON public.tasks FOR DELETE TO authenticated USING (owner_id = auth.uid() OR public.has_role(auth.uid(), 'admin')); CREATE TRIGGER tasks_set_updated_at BEFORE UPDATE ON public.tasks FOR EACH ROW EXECUTE FUNCTION public.set_updated_at(); CREATE INDEX IF NOT EXISTS idx_tasks_owner_done ON public.tasks(owner_id, done);